*** Update File: /app/your_turn/populate_function.cpp
@@
 bool myConstantPropagation(Function &Foo) {
-  // TODO: populate this function.
-  return false;
+  bool Changed = false;
+
+  // Increment the iterator before potentially erasing the current
+  // instruction.  This also naturally handles functions with no blocks.
+  for (BasicBlock &BB : Foo) {
+    for (auto It = BB.begin(), End = BB.end(); It != End;) {
+      Instruction *Inst = &*It++;
+      auto *BinOp = dyn_cast<BinaryOperator>(Inst);
+      if (!BinOp)
+        continue;
+
+      auto *LHS = dyn_cast<ConstantInt>(BinOp->getOperand(0));
+      auto *RHS = dyn_cast<ConstantInt>(BinOp->getOperand(1));
+      if (!LHS || !RHS)
+        continue;
+
+      const APInt &LHSValue = LHS->getValue();
+      const APInt &RHSValue = RHS->getValue();
+      APInt Result(LHSValue.getBitWidth(), 0);
+
+      switch (BinOp->getOpcode()) {
+      case Instruction::Add:
+        Result = LHSValue + RHSValue;
+        break;
+      case Instruction::Sub:
+        Result = LHSValue - RHSValue;
+        break;
+      case Instruction::Mul:
+        Result = LHSValue * RHSValue;
+        break;
+      case Instruction::SDiv:
+        // Both division by zero and INT_MIN / -1 are poison in LLVM IR.
+        if (RHSValue.isZero() ||
+            (LHSValue.isMinSignedValue() && RHSValue.isAllOnes()))
+          continue;
+        Result = LHSValue.sdiv(RHSValue);
+        break;
+      case Instruction::UDiv:
+        if (RHSValue.isZero())
+          continue;
+        Result = LHSValue.udiv(RHSValue);
+        break;
+      case Instruction::Shl:
+      case Instruction::LShr:
+      case Instruction::AShr:
+        // A shift count at least the operand bit width is poison.
+        if (!RHSValue.ult(APInt(RHSValue.getBitWidth(),
+                               LHSValue.getBitWidth())))
+          continue;
+        if (BinOp->getOpcode() == Instruction::Shl)
+          Result = LHSValue.shl(RHSValue.getZExtValue());
+        else if (BinOp->getOpcode() == Instruction::LShr)
+          Result = LHSValue.lshr(RHSValue.getZExtValue());
+        else
+          Result = LHSValue.ashr(RHSValue.getZExtValue());
+        break;
+      case Instruction::And:
+        Result = LHSValue & RHSValue;
+        break;
+      case Instruction::Or:
+        Result = LHSValue | RHSValue;
+        break;
+      case Instruction::Xor:
+        Result = LHSValue ^ RHSValue;
+        break;
+      default:
+        continue;
+      }
+
+      Constant *Folded = ConstantInt::get(cast<IntegerType>(BinOp->getType()),
+                                           Result);
+      BinOp->replaceAllUsesWith(Folded);
+      BinOp->eraseFromParent();
+      Changed = true;
+    }
+  }
+
+  return Changed;
 }
*** End Patch";
